                                counterparty_account_name?: string | null;
                                counterparty_account_nickname?: string | null;
                                /** @description 0 for internal, calculated for external */
                                fee?: number;
                                /** Format: uuid */
                                fee_currency?: string;
                                transaction_amount?: number;
                                /** Format: uuid */
                                transaction_amount_currency?: string;
                                billing_amount?: number;
                                /** Format: uuid */
                                billing_amount_currency?: string;
                                /** @description Always 1 for same-currency transfers */
                                exchange_rate?: number;
                                /** @description 0 for internal, estimated gas for external */
                                network_fee?: number;
